// ── AI CHAT ────────────────────────────────────────────────────────────────
function AIChatPage({ user }) {
  const [msgs, setMsgs] = useState([
    { role: "ai", text: `Hi ${user.name}! 😊 I'm your AI CUSG Expert. Ask me anything — front desk procedures, contacts, expenses, room bookings, legislation, name tags, access cards, and more.` }
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const endRef = useRef(null);

  useEffect(() => { endRef.current?.scrollIntoView({ behavior: "smooth" }); }, [msgs]);

  const send = async () => {
    const text = input.trim();
    if (!text || loading) return;
    setInput("");
    const newMsgs = [...msgs, { role: "user", text }];
    setMsgs(newMsgs);
    setLoading(true);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: SYSTEM_PROMPT,
          messages: newMsgs.map(m => ({ role: m.role === "ai" ? "assistant" : "user", content: m.text }))
        })
      });
      const data = await res.json();
      setMsgs(p => [...p, { role: "ai", text: data.content?.[0]?.text || "Sorry, please try again." }]);
    } catch {
      setMsgs(p => [...p, { role: "ai", text: "Connection error. Please try again." }]);
    }
    setLoading(false);
  };

  return (
    <div className="chat-wrap">
      <div className="chat-header">
        <div className="chat-header-row">
          <h2>Ask AI — CUSG Expert</h2>
          <span className="live-badge">Live</span>
        </div>
        <p>Instant answers on any front desk procedure, inquiry, or CUSG policy — 105th Session.</p>
      </div>

      <div className="chat-msgs">
        {msgs.map((m, i) => (
          <div key={i} className={`msg ${m.role === "user" ? "user" : "ai"}`}>
            <div className="msg-av">
              {m.role === "ai"
                ? <div className="msg-av-ai">AI</div>
                : <div className="msg-av-fb">{user.name[0]}</div>
              }
            </div>
            <div className="bubble">{m.text}</div>
          </div>
        ))}
        {loading && (
          <div className="msg ai">
            <div className="msg-av"><div className="msg-av-ai">AI</div></div>
            <div className="bubble">
              <div className="typing"><div className="dot"/><div className="dot"/><div className="dot"/></div>
            </div>
          </div>
        )}
        <div ref={endRef} />
      </div>

      <div className="chat-footer">
        <textarea
          className="chat-input"
          placeholder="Ask about procedures, contacts, expenses, legislation..."
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); }}}
          rows={1}
        />
        <button className="send-btn" onClick={send} disabled={loading || !input.trim()}>Send</button>
      </div>
    </div>
  );
}

// ── TASKS ──────────────────────────────────────────────────────────────────
const CATS = ["Email", "Mail", "Ordering", "Legislative", "Rooms", "Admin", "Other"];

function TasksPage({ user }) {
  const [tasks, setTasks] = useState(DEFAULT_TASKS);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  // Personal task input
  const [myTxt, setMyTxt] = useState("");
  const [myCat, setMyCat] = useState("Admin");
  const [myPri, setMyPri] = useState("normal");

  // Assign task input (managers only)
  const [asgTxt, setAsgTxt] = useState("");
  const [asgCat, setAsgCat] = useState("Admin");
  const [asgPri, setAsgPri] = useState("normal");
  const [asgTo,  setAsgTo]  = useState("naju1401");

  const STORAGE_KEY = "cusg_shared_tasks";

  // Load from shared persistent storage on mount
  useEffect(() => {
    async function load() {
      try {
        const result = await window.storage.get(STORAGE_KEY, true); // shared=true
        if (result && result.value) {
          setTasks(JSON.parse(result.value));
        }
      } catch {
        // No saved tasks yet — use defaults
      }
      setLoading(false);
    }
    load();
  }, []);

  // Save to shared persistent storage whenever tasks change
  async function saveTasks(newTasks) {
    setTasks(newTasks);
    setSaving(true);
    try {
      await window.storage.set(STORAGE_KEY, JSON.stringify(newTasks), true); // shared=true
    } catch {}
    setSaving(false);
  }

  const getName = k => {
    if (k === "system") return "System";
    return STAFF[k] ? `${STAFF[k].name} ${STAFF[k].last}.` : k;
  };

  const addMine = () => {
    if (!myTxt.trim()) return;
    const newTask = {
      id: Date.now().toString(),
      text: myTxt.trim(),
      category: myCat,
      priority: myPri,
      done: false,
      assignedBy: user.key,
      assignedTo: user.key,
      createdAt: new Date().toISOString(),
    };
    saveTasks([...tasks, newTask]);
    setMyTxt("");
  };

  const addAssigned = () => {
    if (!asgTxt.trim()) return;
    const newTask = {
      id: Date.now().toString(),
      text: asgTxt.trim(),
      category: asgCat,
      priority: asgPri,
      done: false,
      assignedBy: user.key,
      assignedTo: asgTo,
      createdAt: new Date().toISOString(),
    };
    saveTasks([...tasks, newTask]);
    setAsgTxt("");
  };

  const tog = id => saveTasks(tasks.map(t => t.id === id ? { ...t, done: !t.done } : t));
  const del = id => saveTasks(tasks.filter(t => t.id !== id));

  // What this user sees
  const assignedToMe = tasks.filter(t =>
    !t.done &&
    t.assignedTo === user.key &&
    t.assignedBy !== user.key &&
    t.assignedBy !== "system"
  );
  const myPersonal = tasks.filter(t =>
    !t.done &&
    t.assignedBy === user.key &&
    t.assignedTo === user.key
  );
  const systemTasks = tasks.filter(t =>
    !t.done && t.assignedBy === "system"
  );
  const doneTasks = tasks.filter(t =>
    t.done && (
      t.assignedTo === user.key ||
      t.assignedBy === user.key ||
      t.assignedBy === "system"
    )
  );

  // All tasks for manager view
  const allPending = tasks.filter(t => !t.done);
  const allDone = tasks.filter(t => t.done);

  const TaskItem = ({ t, showAssignee = false }) => {
    const fromManager = t.assignedBy !== user.key && t.assignedBy !== "system";
    const canDel = t.assignedBy === user.key || user.canAssign;
    return (
      <div className={`task-item${t.done ? " done" : ""}${fromManager ? " from-manager" : ""}`}>
        <div className={`chk${t.done ? " on" : ""}`} onClick={() => tog(t.id)}>
          {t.done && "✓"}
        </div>
        <div className="task-body">
          <div className={`task-text${t.done ? " done" : ""}`}>{t.text}</div>
          <div className="task-meta">
            <span className="tag tag-cat">{t.category}</span>
            {t.priority === "high" && <span className="tag tag-high">High Priority</span>}
            {fromManager && <span className="tag tag-assigned">From {getName(t.assignedBy)}</span>}
            {showAssignee && t.assignedBy !== "system" && (
              <span className="tag tag-to">&#8594; {getName(t.assignedTo)}</span>
            )}
          </div>
        </div>
        {canDel && <button className="del-btn" onClick={() => del(t.id)}>&#215;</button>}
      </div>
    );
  };

  if (loading) return (
    <div className="page" style={{ display: "flex", alignItems: "center", justifyContent: "center", minHeight: 200 }}>
      <p style={{ color: "var(--text3)", fontSize: 14 }}>Loading tasks...</p>
    </div>
  );

  // ── MANAGER VIEW ──────────────────────────────────────────────────────────
  if (user.canAssign) {
    return (
      <div className="page">
        <div className="ph">
          <h2>Tasks</h2>
          <p style={{ color: saving ? "var(--cu-gold-dark)" : "var(--text3)" }}>
            {saving ? "Saving..." : `${allPending.length} pending across all staff`}
          </p>
          <div className="ph-bar" />
        </div>

        {/* ASSIGN TO STAFF */}
        <div className="task-section-label">Assign a Task to Front Desk Staff</div>
        <div className="add-area" style={{ marginBottom: 28 }}>
          <div className="add-row">
            <input className="t-inp" placeholder="Write a task for staff..."
              value={asgTxt} onChange={e => setAsgTxt(e.target.value)}
              onKeyDown={e => e.key === "Enter" && addAssigned()} />
            <select className="sel" value={asgCat} onChange={e => setAsgCat(e.target.value)}>
              {CATS.map(c => <option key={c}>{c}</option>)}
            </select>
            <select className="sel" value={asgPri} onChange={e => setAsgPri(e.target.value)}>
              <option value="normal">Normal</option>
              <option value="high">High Priority</option>
            </select>
          </div>
          <div className="assign-row" style={{ marginTop: 10 }}>
            <span className="assign-lbl">Send to:</span>
            <select className="sel" value={asgTo} onChange={e => setAsgTo(e.target.value)}>
              <option value="naju1401">Natalie J.</option>
              <option value="sabi7853">Sania B.</option>
              <option value="lesc6672">Levi S.</option>
            </select>
            <button className="add-btn" onClick={addAssigned}>Send Task</button>
          </div>
        </div>

        {/* MY PERSONAL TASKS */}
        <div className="task-section-label">My Personal Tasks</div>
        <div className="add-area" style={{ marginBottom: 12 }}>
          <div className="add-row">
            <input className="t-inp" placeholder="Add your own task..."
              value={myTxt} onChange={e => setMyTxt(e.target.value)}
              onKeyDown={e => e.key === "Enter" && addMine()} />
            <select className="sel" value={myCat} onChange={e => setMyCat(e.target.value)}>
              {CATS.map(c => <option key={c}>{c}</option>)}
            </select>
            <button className="add-btn" onClick={addMine}>+ Add</button>
          </div>
        </div>
        <div className="task-list" style={{ marginBottom: 28 }}>
          {myPersonal.length === 0
            ? <p style={{ color: "var(--text3)", fontSize: 13 }}>No personal tasks.</p>
            : myPersonal.map(t => <TaskItem key={t.id} t={t} />)
          }
        </div>

        {/* ALL STAFF TASKS */}
        <div className="task-section-label">All Staff Tasks</div>
        <div className="task-list" style={{ marginBottom: 24 }}>
          {allPending.filter(t => t.assignedBy !== user.key || t.assignedTo !== user.key).map(t => (
            <TaskItem key={t.id} t={t} showAssignee />
          ))}
          {allPending.filter(t => t.assignedBy !== user.key || t.assignedTo !== user.key).length === 0 && (
            <p style={{ color: "var(--text3)", fontSize: 13 }}>No tasks assigned to staff yet.</p>
          )}
        </div>

        {allDone.length > 0 && (
          <>
            <div className="task-section-label">Completed</div>
            <div className="task-list">
              {allDone.map(t => <TaskItem key={t.id} t={t} showAssignee />)}
            </div>
          </>
        )}
      </div>
    );
  }

  // ── STAFF VIEW ────────────────────────────────────────────────────────────
  return (
    <div className="page">
      <div className="ph">
        <h2>Tasks</h2>
        <p style={{ color: saving ? "var(--cu-gold-dark)" : "var(--text3)" }}>
          {saving ? "Saving..." : `${assignedToMe.length + myPersonal.length + systemTasks.length} pending`}
        </p>
        <div className="ph-bar" />
      </div>

      {/* TASKS FROM YOUR MANAGER */}
      {assignedToMe.length > 0 && (
        <>
          <div className="task-section-label">From Your Manager</div>
          <div className="task-list" style={{ marginBottom: 24 }}>
            {assignedToMe.map(t => <TaskItem key={t.id} t={t} />)}
          </div>
        </>
      )}

      {/* DAILY CHECKLIST */}
      {systemTasks.length > 0 && (
        <>
          <div className="task-section-label">Daily Checklist</div>
          <div className="task-list" style={{ marginBottom: 24 }}>
            {systemTasks.map(t => <TaskItem key={t.id} t={t} />)}
          </div>
        </>
      )}

      {/* MY PERSONAL TASKS */}
      <div className="task-section-label">My Tasks</div>
      <div className="add-area" style={{ marginBottom: 12 }}>
        <div className="add-row">
          <input className="t-inp" placeholder="Add your own task..."
            value={myTxt} onChange={e => setMyTxt(e.target.value)}
            onKeyDown={e => e.key === "Enter" && addMine()} />
          <select className="sel" value={myCat} onChange={e => setMyCat(e.target.value)}>
            {CATS.map(c => <option key={c}>{c}</option>)}
          </select>
          <select className="sel" value={myPri} onChange={e => setMyPri(e.target.value)}>
            <option value="normal">Normal</option>
            <option value="high">High Priority</option>
          </select>
          <button className="add-btn" onClick={addMine}>+ Add</button>
        </div>
      </div>
      <div className="task-list" style={{ marginBottom: 24 }}>
        {myPersonal.length === 0
          ? <p style={{ color: "var(--text3)", fontSize: 13 }}>No personal tasks yet. Add one above.</p>
          : myPersonal.map(t => <TaskItem key={t.id} t={t} />)
        }
      </div>

      {doneTasks.length > 0 && (
        <>
          <div className="task-section-label">Completed</div>
          <div className="task-list">
            {doneTasks.map(t => <TaskItem key={t.id} t={t} />)}
          </div>
        </>
      )}
    </div>
  );
}


