// ── ROOT ───────────────────────────────────────────────────────────────────
export default function App() {
  const [user, setUser] = useState(() => {
    // Auto-restore saved session
    try {
      const saved = localStorage.getItem("cusg_user");
      if (saved && STAFF[saved]) return { key: saved, ...STAFF[saved] };
    } catch {}
    return null;
  });
  const [tab, setTab] = useState("home");

  const NAV = [
    { id: "home",     icon: "&#x2302;",  label: "Dashboard" },
    { id: "ai",       icon: "&#x2726;",  label: "Ask AI — CUSG Expert" },
    { id: "tasks",    icon: "&#x2713;",  label: "Tasks" },
    { id: "email",    icon: "&#x2709;",  label: "Email Inboxes" },
    { id: "teams",    icon: "&#x1F4C2;", label: "Resources & Files" },
    { id: "contacts", icon: "&#x260E;",  label: "Directory" },
  ];

  const signOut = () => {
    localStorage.removeItem("cusg_user");
    setUser(null);
    setTab("home");
  };

  const renderPage = () => {
    if (tab === "home")     return <WelcomePage user={user} setTab={setTab} />;
    if (tab === "email")    return <EmailPage />;
    if (tab === "ai")       return <AIChatPage user={user} />;
    if (tab === "tasks")    return <TasksPage user={user} />;
    if (tab === "teams")    return <TeamsPage />;
    if (tab === "contacts") return <ContactsPage />;
  };

  if (!user) return <><style>{CSS}</style><LoginPage onLogin={setUser} /></>;

  return (
    <><style>{CSS}</style>
    <div className="shell">
      <aside className="sidebar">
        <div className="sb-header">
          <img src={LOGO} alt="CUSG" className="sb-logo" />
          <div className="sb-brand">
            <div className="sb-eye">CUSG</div>
            <div className="sb-name">Front Desk</div>
          </div>
        </div>
        <div className="sb-session">105th Session &middot; Staff Portal</div>

        <nav className="sb-nav">
          {NAV.map(n => (
            <button key={n.id} className={`nav-btn${tab === n.id ? " active" : ""}`} onClick={() => setTab(n.id)}>
              <span className="nav-icon" dangerouslySetInnerHTML={{ __html: n.icon }} />
              {n.label}
            </button>
          ))}
        </nav>

        <div className="sb-footer">
          <div className="user-card">
            <div className="user-av">
              <div className="user-av-fb">{user.name[0]}</div>
            </div>
            <div className="user-info">
              <div className="user-name">{displayName(user)}</div>
              <div className="user-role">{user.role}</div>
            </div>
            <button className="signout-btn" onClick={signOut}>Sign out</button>
          </div>
        </div>
      </aside>

      <main className="main">{renderPage()}</main>
    </div></>
  );
}
